var e=JSON.parse(`[{"id":"L1_1","type":"subtitle","speaker":null,"text":{"KOREA":"CN No. FRMC001L00767-01\\n<color=#ffd34c>3급 요인</color> 열람 승인 자료\\n대상자 이력","JPN":"CN No. FRMC001L00767-01\\n<color=#ffd34c>3級要因</color> 閲覧承認資料\\n対象者履歴","ENG":"CN No. FRMC001L00767-01\\n<color=#ffd34c>Class 3 Subject</color> Access Approval Documents\\nSubject History","TWN":"(TWN)CN No. FRMC001L00767-01\\n<color=#ffd34c>3급 요인</color> 열람 승인 자료\\n대상자 이력"},"stage":{"bg":"BLACK","bgm":null,"filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L3_1","type":"dialog","speaker":"SOUNDALPHA_VOICE_NULL_NULL","text":{"KOREA":"무임승차나 하게 내버려 두긴 아까운 인재야.\\n출신은 어딘가.","JPN":"ただ乗りもするようにほったらかすことは惜しい人材なの。\\n出身はどこか。","ENG":"She's too talented to let freeload.\\nWhere's she from?","TWN":"(TWN)무임승차나 하게 내버려 두긴 아까운 인재야.\\n출신은 어딘가."},"stage":{"bg":"BLACK","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AMY_FREEDOM_NULL_NULL","face":"UNIT_IDLE","hologram":false},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"SOUNDBETA_VOICE_NULL_NULL","text":{"KOREA":"미국입니다. 부친은 인근 사립 초등학교의 교사로 재직 중이고 모친은 작은 식료품점을 운영한다는군요. ","JPN":"米国です。父親は近隣私立小学校の教師で在職中で母親は小さな食料品店を運営するんですって。","ENG":"The United States. Her father works as a teacher at a nearby private elementary school, and her mother runs a small grocery store.","TWN":"(TWN)미국입니다. 부친은 인근 사립 초등학교의 교사로 재직 중이고 모친은 작은 식료품점을 운영한다는군요. "},"stage":{"bg":"BLACK","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AMY_FREEDOM_NULL_NULL","face":"UNIT_IDLE","hologram":false},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"SOUNDALPHA_VOICE_NULL_NULL","text":{"KOREA":"꽤 풍족한 집안에서 태어났군.","JPN":"かなり豊かな家で生まれたな。","ENG":"Born into quite a well-off family.","TWN":"(TWN)꽤 풍족한 집안에서 태어났군."},"stage":{"bg":"BLACK","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AMY_FREEDOM_NULL_NULL","face":"UNIT_IDLE","hologram":false},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"SOUNDALPHA_VOICE_NULL_NULL","text":{"KOREA":"그런 환경에서 살다가 프리라이더와 어울리긴 쉽지 않았을 텐데.","JPN":"そんな環境で生きてフリーライダーと交わることは容易でなかったのに。","ENG":"Must have been hard to fit in with the Freedom Riders, coming from that background.","TWN":"(TWN)그런 환경에서 살다가 프리라이더와 어울리긴 쉽지 않았을 텐데."},"stage":{"bg":"BLACK","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AMY_FREEDOM_NULL_NULL","face":"UNIT_IDLE","hologram":false},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"SOUNDBETA_VOICE_NULL_NULL","text":{"KOREA":"글쎄요. 성격이 그렇게 착하면 오히려 측은지심이 폭발하지 않았을까요.","JPN":"そうですね。性格がそのように善良ならばむしろ惻隠之心が爆発しなかったんでしょうか。","ENG":"Perhaps. If she's that kind-hearted, her compassion might have exploded instead.","TWN":"(TWN)글쎄요. 성격이 그렇게 착하면 오히려 측은지심이 폭발하지 않았을까요."},"stage":{"bg":"BLACK","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AMY_FREEDOM_NULL_NULL","face":"UNIT_IDLE","hologram":false},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"SOUNDBETA_VOICE_NULL_NULL","text":{"KOREA":"그리고 프리덤 라이더즈의 설립 목적은 상부상조입니다.\\n네트워크 마케팅에서 쓰는 표어와 다를 바 없지만요.","JPN":"そしてフリーダムライダーズの設立目的は持ちつ持たれつです。\\nネトワークマーケティングで使う標語と違うところないけれども。","ENG":"Besides, the Freedom Riders were founded on mutual aid.\\nNot that different from network marketing slogans, though.","TWN":"(TWN)그리고 프리덤 라이더즈의 설립 목적은 상부상조입니다.\\n네트워크 마케팅에서 쓰는 표어와 다를 바 없지만요."},"stage":{"bg":"BLACK","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AMY_FREEDOM_NULL_NULL","face":"UNIT_IDLE","hologram":false},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"SOUNDALPHA_VOICE_NULL_NULL","text":{"KOREA":"그러니까, 자네 말은 봉사 활동 하자고 저기 들어갔단 건가?\\n갈 수 있으면 지옥불 속에라도 뛰어들겠군.","JPN":"そうするから、君の言葉はボランティア活動しようとあの入ったという濃いか?\\n行くことができれば地獄ドル中にでも跳び込むね。","ENG":"So you're saying she joined up to volunteer?\\nShe'd jump into hellfire if she could.","TWN":"(TWN)그러니까, 자네 말은 봉사 활동 하자고 저기 들어갔단 건가?\\n갈 수 있으면 지옥불 속에라도 뛰어들겠군."},"stage":{"bg":"BLACK","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AMY_FREEDOM_NULL_NULL","face":"UNIT_IDLE","hologram":false},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"SOUNDALPHA_VOICE_NULL_NULL","text":{"KOREA":"각성에 특별한 동기는 없었나?","JPN":"覚醒に特別な同期はなかったか?","ENG":"No special trigger for her awakening?","TWN":"(TWN)각성에 특별한 동기는 없었나?"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AMY_FREEDOM_NULL_NULL","face":"UNIT_IDLE","hologram":false},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"SOUNDBETA_VOICE_NULL_NULL","text":{"KOREA":"보드 스팟에서 퍼포먼스 연습 중에 갑자기 힘이 생겼다고 하네요. ","JPN":"ボードスポットでパフォーマンス練習中に急に力が生じたと言いますね。","ENG":"She suddenly manifested powers while practicing tricks at a board spot.","TWN":"(TWN)보드 스팟에서 퍼포먼스 연습 중에 갑자기 힘이 생겼다고 하네요. "},"stage":{"bg":"BLACK","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AMY_FREEDOM_NULL_NULL","face":"UNIT_IDLE","hologram":false},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"SOUNDBETA_VOICE_NULL_NULL","text":{"KOREA":"그리고 기왕 생긴 힘이니 다른 사람들을 돕고 싶다고 응답했습니다.","JPN":"そして既往生じた力だから他の人々を助けたいと応答しました。","ENG":"And she said she wanted to use her newfound powers to help others.","TWN":"(TWN)그리고 기왕 생긴 힘이니 다른 사람들을 돕고 싶다고 응답했습니다."},"stage":{"bg":"BLACK","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AMY_FREEDOM_NULL_NULL","face":"UNIT_IDLE","hologram":false},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"SOUNDALPHA_VOICE_NULL_NULL","text":{"KOREA":"호오, 그래서 산타클로스가 선물은 줬다던가?","JPN":"好悪、それでサンタクロースが贈り物はジュオッダドンガ?","ENG":"Hmph, so Santa Claus gave her a gift?","TWN":"(TWN)호오, 그래서 산타클로스가 선물은 줬다던가?"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AMY_FREEDOM_NULL_NULL","face":"UNIT_IDLE","hologram":false},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"SOUNDBETA_VOICE_NULL_NULL","text":{"KOREA":"그 영감님은 경영 악화로 폐업한 지 꽤 됐을 텐데요.","JPN":"その老台は経営悪化で閉業してからかなりなったと思いますが。","ENG":"That old man would have gone out of business due to poor management ages ago.","TWN":"(TWN)그 영감님은 경영 악화로 폐업한 지 꽤 됐을 텐데요."},"stage":{"bg":"BLACK","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AMY_FREEDOM_NULL_NULL","face":"UNIT_IDLE","hologram":false},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"SOUNDBETA_VOICE_NULL_NULL","text":{"KOREA":"스트릭랜드 양은 세상을 바라보는 관점이 다를 겁니다.","JPN":"ストリックレンド量は世の中を眺める観点が違うでしょう。","ENG":"Miss Strickland sees the world differently.","TWN":"(TWN)스트릭랜드 양은 세상을 바라보는 관점이 다를 겁니다."},"stage":{"bg":"BLACK","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AMY_FREEDOM_NULL_NULL","face":"UNIT_IDLE","hologram":false},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"SOUNDBETA_VOICE_NULL_NULL","text":{"KOREA":"사람은 자기 생활이 풍족할수록 진취적이고 너그러워지니까요.","JPN":"人は自分の生活が豊かであるほど進取的で寛大になるからです。","ENG":"People become more enterprising and generous when their lives are abundant.","TWN":"(TWN)사람은 자기 생활이 풍족할수록 진취적이고 너그러워지니까요."},"stage":{"bg":"BLACK","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AMY_FREEDOM_NULL_NULL","face":"UNIT_IDLE","hologram":false},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"SOUNDBETA_VOICE_NULL_NULL","text":{"KOREA":"여태까지 제가 만나 본 사람들도 인품과 주머니의 두께가 정비례했습니다.","JPN":"女振りまで私が会ってみた人々も人柄とポケットの厚さが整備例しました。","ENG":"In my experience, character is proportional to wallet thickness.","TWN":"(TWN)여태까지 제가 만나 본 사람들도 인품과 주머니의 두께가 정비례했습니다."},"stage":{"bg":"BLACK","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AMY_FREEDOM_NULL_NULL","face":"UNIT_IDLE","hologram":false},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"SOUNDALPHA_VOICE_NULL_NULL","text":{"KOREA":"안 본 사이 너무 야박해졌어, 자네.","JPN":"見なかった間とても世知辛くなった、君。","ENG":"You've become quite cynical since we last spoke.","TWN":"(TWN)안 본 사이 너무 야박해졌어, 자네."},"stage":{"bg":"BLACK","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AMY_FREEDOM_NULL_NULL","face":"UNIT_IDLE","hologram":false},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"SOUNDBETA_VOICE_NULL_NULL","text":{"KOREA":"사실을 얘기한 겁니다.","JPN":"事実を話しました。","ENG":"I'm just stating facts.","TWN":"(TWN)사실을 얘기한 겁니다."},"stage":{"bg":"BLACK","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AMY_FREEDOM_NULL_NULL","face":"UNIT_IDLE","hologram":false},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"SOUNDALPHA_VOICE_NULL_NULL","text":{"KOREA":"가끔은 입에 발린 말도 필요한 걸세.","JPN":"たまには口先だけも匹ヨハン濃にしよう。","ENG":"Sometimes a little sugar-coating is necessary.","TWN":"(TWN)가끔은 입에 발린 말도 필요한 걸세."},"stage":{"bg":"BLACK","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AMY_FREEDOM_NULL_NULL","face":"UNIT_IDLE","hologram":false},"R":null}}}]`);export{e as default};